/**
 * Block editor integration — shows source release attribution
 * in the Post Status panel for posts generated by this plugin.
 */

import { registerPlugin } from '@wordpress/plugins';
import { PluginPostStatusInfo } from '@wordpress/edit-post';
import { useEntityProp } from '@wordpress/core-data';
import { useSelect } from '@wordpress/data';
import { __ } from '@wordpress/i18n';
import { ExternalLink } from '@wordpress/components';

/**
 * Renders a "Generated from GitHub plugin release" line in the
 * Status & Visibility panel when the current post has source meta.
 */
function ReleaseAttribution() {
	const postType = useSelect(
		( select ) => select( 'core/editor' ).getCurrentPostType(),
		[]
	);

	const [ sourceRepo ] = useEntityProp( 'postType', postType, 'meta' );

	if ( ! sourceRepo ) {
		return null;
	}

	const repo = sourceRepo._ctbp_source_repo || '';
	const tag = sourceRepo._ctbp_release_tag || '';
	const releaseUrl = sourceRepo._ctbp_release_url || '';

	if ( ! repo || ! releaseUrl ) {
		return null;
	}

	return (
		<PluginPostStatusInfo className="ctbp-release-attribution">
			<span>
				{ __( 'Generated from', 'changelog-to-blog-post' ) }{ ' ' }
				<ExternalLink href={ releaseUrl }>
					{ __( 'GitHub plugin release', 'changelog-to-blog-post' ) }
				</ExternalLink>
				{ tag && (
					<span style={ { color: '#757575', marginLeft: '4px' } }>
						({ repo } { tag })
					</span>
				) }
			</span>
		</PluginPostStatusInfo>
	);
}

registerPlugin( 'ctbp-release-attribution', {
	render: ReleaseAttribution,
} );
